const body = $json.body || $json;
const driveLink = body.driveLink || '';
const token = body.googleAccessToken || '';
if (!driveLink) throw new Error('driveLink is required');
if (!token) throw new Error('googleAccessToken is required');
const m1 = driveLink.match(/\/d\/([a-zA-Z0-9_-]+)/);
const m2 = driveLink.match(/[?&]id=([a-zA-Z0-9_-]+)/);
const fileId = (m1 && m1[1]) || (m2 && m2[1]) || '';
if (!fileId) throw new Error('Could not parse Drive file ID from: ' + driveLink);
return { json: { driveLink, token, fileId } };

const meta = $json;
const row = $('Parse Request Body').item.json;

if (meta.error) {
  const code = meta.error.code || 0;
  const status =
    code === 401
      ? 'Error: Google session expired — sign out and sign in again'
      : 'Error: Drive file not accessible (check permissions)';
  return {
    json: { ...row, _mimeType: '', _fileName: '', _fileClass: 'error', _status: status, _downloadUrl: '' },
  };
}

const mime = meta.mimeType || '';
const fileId = row.fileId || '';
let fileClass = 'document';
let status = '';
let exportAsPdf = false;

if (mime.startsWith('image/')) {
  fileClass = 'image';
} else if (mime.startsWith('application/vnd.google-apps.')) {
  fileClass = 'document';
  exportAsPdf = true;
} else if (!mime) {
  fileClass = 'error';
  status = 'Error: Drive file not accessible (check permissions)';
} else {
  fileClass = 'document';
}

let downloadUrl = '';
if (fileId && fileClass !== 'error') {
  downloadUrl = exportAsPdf
    ? `https://www.googleapis.com/drive/v3/files/${fileId}/export?mimeType=application%2Fpdf`
    : `https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`;
}

return {
  json: {
    ...row,
    _mimeType: mime,
    _fileName: meta.name || '',
    _fileClass: fileClass,
    _status: status,
    _downloadUrl: downloadUrl,
  },
};

const OFFICE_DOC_MIMES = new Set([
  'application/msword',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
]);

function isOfficeDocMime(mime, fileName) {
  return OFFICE_DOC_MIMES.has(mime) || /\.docx?$/i.test(fileName || '');
}

function getDriveCredentials(row) {
  return {
    fileId: row._fileId || row.fileId || '',
    token: row._token || row.token || '',
  };
}

async function convertOfficeDocToPdf(fileId, token, fileName) {
  let copyId = '';
  try {
    const copy = await this.helpers.httpRequest({
      method: 'POST',
      url: `https://www.googleapis.com/drive/v3/files/${fileId}/copy`,
      headers: {
        Authorization: `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      body: {
        mimeType: 'application/vnd.google-apps.document',
        name: `__ledgerlens_convert_${fileId}`,
      },
      json: true,
    });
    copyId = copy.id;

    const pdfBuffer = await this.helpers.httpRequest({
      method: 'GET',
      url: `https://www.googleapis.com/drive/v3/files/${copyId}/export?mimeType=application/pdf`,
      headers: { Authorization: `Bearer ${token}` },
      encoding: 'arraybuffer',
    });

    const pdfName = (fileName || 'invoice').replace(/\.[^.]+$/i, '') + '.pdf';
    return await this.helpers.prepareBinaryData(pdfBuffer, pdfName, 'application/pdf');
  } finally {
    if (copyId && token) {
      try {
        await this.helpers.httpRequest({
          method: 'DELETE',
          url: `https://www.googleapis.com/drive/v3/files/${copyId}`,
          headers: { Authorization: `Bearer ${token}` },
        });
      } catch (_) {}
    }
  }
}

const row = $('Classify MimeType').item.json;
const binData = $binary?.invoiceFile || null;

// #region agent log
fetch('http://127.0.0.1:7278/ingest/2c22404a-379e-4acd-837f-babf35680249',{method:'POST',headers:{'Content-Type':'application/json','X-Debug-Session-Id':'eec9f5'},body:JSON.stringify({sessionId:'eec9f5',location:'restoreRowAfterDownload.js:entry',message:'restore entry',data:{idx:row._idx,mime:row._mimeType,fileName:row._fileName,hasBinary:!!binData,isOffice:isOfficeDocMime(row._mimeType||'',row._fileName||'')},timestamp:Date.now(),hypothesisId:'H1'})}).catch(()=>{});
// #endregion

if (!binData) {
  return {
    json: {
      ...row,
      _status: 'Error: file download failed (check Drive permissions)',
      _downloadFailed: true,
    },
  };
}

const mime = row._mimeType || binData.mimeType || '';
const fileName = row._fileName || binData.fileName || '';

if (!isOfficeDocMime(mime, fileName)) {
  return { json: { ...row, _downloadFailed: false }, binary: { invoiceFile: binData } };
}

const { fileId, token } = getDriveCredentials(row);
if (!fileId || !token) {
  return {
    json: {
      ...row,
      _status: 'Error: missing Drive file ID or token for DOC/DOCX conversion',
      _downloadFailed: true,
    },
  };
}

try {
  const pdfBinary = await convertOfficeDocToPdf.call(this, fileId, token, fileName);
  // #region agent log
  fetch('http://127.0.0.1:7278/ingest/2c22404a-379e-4acd-837f-babf35680249',{method:'POST',headers:{'Content-Type':'application/json','X-Debug-Session-Id':'eec9f5'},body:JSON.stringify({sessionId:'eec9f5',location:'restoreRowAfterDownload.js:converted',message:'DOCX converted to PDF',data:{idx:row._idx,fileId,converted:true},timestamp:Date.now(),hypothesisId:'H1'})}).catch(()=>{});
  // #endregion
  return {
    json: {
      ...row,
      _downloadFailed: false,
      _geminiMimeType: 'application/pdf',
      _convertedFromOffice: true,
    },
    binary: { invoiceFile: pdfBinary },
  };
} catch (e) {
  const msg = String(e.message || e);
  const needsReauth = /403|401|insufficient|permission|scope/i.test(msg);
  return {
    json: {
      ...row,
      _status: needsReauth
        ? 'Error: DOC/DOCX conversion needs Drive write access — sign out and sign in again'
        : 'Error: could not convert DOC/DOCX to PDF — ' + msg,
      _downloadFailed: true,
    },
  };
}

const OPENROUTER_MODEL = 'nvidia/nemotron-nano-12b-v2-vl:free';

const EXTRACTION_PROMPT = `You are reading an invoice document. Extract ONLY these four fields and return valid JSON with no prose, no markdown, no code fences:

{"payee":"string","account_number":"string","ifsc":"string","amount":"string","confidence":0.0}

Rules:
- payee: the account payee or beneficiary name exactly as printed on THIS invoice
- account_number: digits only, no spaces or dashes — copy exactly from the document
- ifsc: exactly 11 characters, uppercase, copied from the document (format: 4 letters + 0 + 6 alphanumeric)
- amount: invoice total or grand total as printed (digits and decimal point only, no currency symbols or commas)
- confidence: 0.0 to 1.0 — use 0.0 if you cannot read the document clearly
- If a field is missing or unreadable, use "" and set confidence below 0.5
- NEVER invent, guess, or reuse placeholder values — only copy text visible on the invoice`;

const row = $('Restore Row After Download').item.json;

if (row._downloadFailed) {
  // #region agent log
  fetch('http://127.0.0.1:7278/ingest/2c22404a-379e-4acd-837f-babf35680249',{method:'POST',headers:{'Content-Type':'application/json','X-Debug-Session-Id':'eec9f5'},body:JSON.stringify({sessionId:'eec9f5',location:'prepareOpenRouterPayload.js:skip',message:'skip openrouter download failed',data:{idx:row._idx,status:row._status},timestamp:Date.now(),hypothesisId:'H1'})}).catch(()=>{});
  // #endregion
  return { json: { error: row._status || 'Invoice file unavailable', _skipOpenRouter: true } };
}

if (row._officeDocText) {
  const _openRouterBody = {
    model: OPENROUTER_MODEL,
    max_tokens: 1024,
    messages: [
      {
        role: 'user',
        content:
          EXTRACTION_PROMPT +
          '\n\n--- Invoice document text ---\n' +
          row._officeDocText,
      },
    ],
  };
  return {
    json: {
      _openRouterBody,
      _openRouterModel: OPENROUTER_MODEL,
      _prepareMime: 'text/plain',
      _prepareIdx: row._idx,
      _prepareMode: 'text',
    },
  };
}

const bin = $binary?.invoiceFile || null;
if (!bin) {
  return { json: { error: 'No invoice file binary found for OpenRouter analysis' } };
}

const buffer = await this.helpers.getBinaryDataBuffer(0, 'invoiceFile');
const base64 = Buffer.from(buffer).toString('base64');

let mime = row._geminiMimeType || row._mimeType || bin.mimeType || 'application/octet-stream';

if (mime === 'application/octet-stream' && row._fileClass === 'image') {
  mime = 'image/jpeg';
}

const dataUrl = `data:${mime};base64,${base64}`;

function buildVisionContent(prompt) {
  if (mime === 'application/pdf') {
    return [
      {
        type: 'file',
        file: {
          filename: 'invoice.pdf',
          file_data: dataUrl,
        },
      },
      { type: 'text', text: prompt },
    ];
  }

  return [
    {
      type: 'image_url',
      image_url: { url: dataUrl },
    },
    { type: 'text', text: prompt },
  ];
}

const _openRouterBody = {
  model: OPENROUTER_MODEL,
  max_tokens: 1024,
  messages: [
    {
      role: 'user',
      content: buildVisionContent(EXTRACTION_PROMPT),
    },
  ],
};

// #region agent log
fetch('http://127.0.0.1:7278/ingest/2c22404a-379e-4acd-837f-babf35680249',{method:'POST',headers:{'Content-Type':'application/json','X-Debug-Session-Id':'eec9f5'},body:JSON.stringify({sessionId:'eec9f5',location:'prepareOpenRouterPayload.js:vision',message:'openrouter body prepared',data:{idx:row._idx,mime,mode:'vision',base64Len:base64.length},timestamp:Date.now(),hypothesisId:'H2'})}).catch(()=>{});
// #endregion

return {
  json: {
    _openRouterBody,
    _openRouterModel: OPENROUTER_MODEL,
    _prepareMime: mime,
    _prepareIdx: row._idx,
    _prepareMode: 'vision',
  },
};

const row = $('Restore Row After Download').item.json;
if (row._downloadFailed) {
  return { json: { payee: '', accountNumber: '', ifsc: '', amount: '', confidence: 0, status: row._status } };
}

function formatError(err) {
  if (err == null || err === '') return 'unknown error';
  if (typeof err === 'string') return err;
  return err.message || JSON.stringify(err);
}

function getPrepareError() {
  const analyzeNode =
    row._fileClass === 'image' ? 'OpenRouter Analyze Image' : 'OpenRouter Analyze Document';
  try {
    const prep = $(analyzeNode).item?.json;
    if (prep?.error) return formatError(prep.error);
  } catch (_) {}
  return '';
}

const prepareError = getPrepareError();
if (prepareError) {
  return {
    json: {
      payee: '',
      accountNumber: '',
      ifsc: '',
      amount: '',
      confidence: 0,
      status: 'Error: extraction analyze failed - ' + prepareError,
    },
  };
}

if ($json.error) {
  return {
    json: {
      payee: '',
      accountNumber: '',
      ifsc: '',
      amount: '',
      confidence: 0,
      status: 'Error: extraction analyze failed - ' + formatError($json.error),
    },
  };
}

function extractRawModelText(data) {
  if (!data) return '';
  if (typeof data.text === 'string') return data.text;
  if (typeof data.output === 'string') return data.output;
  if (typeof data.content === 'string') return data.content;
  const openAiContent = data.choices?.[0]?.message?.content;
  if (typeof openAiContent === 'string') return openAiContent;
  const openAiText = data.choices?.[0]?.text;
  if (typeof openAiText === 'string') return openAiText;
  const messageContent = data.message?.content;
  if (typeof messageContent === 'string') return messageContent;
  const partText = data.content?.parts?.[0]?.text;
  if (typeof partText === 'string') return partText;
  return '';
}

function normalizeAmount(val) {
  const s = String(val ?? '').trim();
  if (!s) return '';
  return s.replace(/[^\d.]/g, '');
}

const PROMPT_LEAKED_IFSC = 'HDFC0001234';
const IFSC_REGEX = /^[A-Z]{4}0[A-Z0-9]{6}$/;

function detectHallucination(payee, acct, ifsc, confidence) {
  if (ifsc === PROMPT_LEAKED_IFSC) return 'model returned prompt example IFSC';
  if (/^123456789012$/.test(acct)) return 'placeholder account number';
  if (acct.length >= 10 && /^(\d)\1+$/.test(acct)) return 'repeated-digit account number';
  if (ifsc && !IFSC_REGEX.test(ifsc)) return 'invalid IFSC format';
  if (confidence < 0.5 && payee && acct) return 'low confidence with filled fields';
  return '';
}

function parseExtractionPayload(data) {
  if (
    data.payee !== undefined ||
    data.account_number !== undefined ||
    data.ifsc !== undefined ||
    data.amount !== undefined ||
    data.total !== undefined
  ) {
    return data;
  }
  const raw = extractRawModelText(data);
  if (!raw) return null;
  const cleaned = raw.replace(/```json?\n?/gi, '').replace(/```/g, '').trim();
  return JSON.parse(cleaned);
}

try {
  const p = parseExtractionPayload($json);
  if (!p) {
    return {
      json: {
        payee: '',
        accountNumber: '',
        ifsc: '',
        amount: '',
        confidence: 0,
        status: 'Error: model returned empty extraction',
      },
    };
  }

  if (p.error) {
    return {
      json: {
        payee: '',
        accountNumber: '',
        ifsc: '',
        amount: '',
        confidence: 0,
        status: 'Error: extraction analyze failed - ' + p.error,
      },
    };
  }

  const payee = String(p.payee || '').trim();
  const accountNumber = String(p.account_number || p.bank_number || p.bank_account_number || '')
    .replace(/\D/g, '');
  const ifsc = String(p.ifsc || '').toUpperCase().trim();
  const amount = normalizeAmount(
    p.amount ?? p.total ?? p.total_amount ?? p.invoice_amount ?? p.invoice_total
  );
  const confidence = typeof p.confidence === 'number' ? p.confidence : 0;

  const hallucinationReason = detectHallucination(payee, accountNumber, ifsc, confidence);
  if (hallucinationReason) {
    return {
      json: {
        payee: '',
        accountNumber: '',
        ifsc: '',
        amount: '',
        confidence,
        status: 'Error: model returned unreliable extraction - ' + hallucinationReason,
      },
    };
  }

  if (!payee && !accountNumber && !ifsc && !amount) {
    return {
      json: {
        payee: '',
        accountNumber: '',
        ifsc: '',
        amount: '',
        confidence,
        status: 'Error: model returned empty extraction',
      },
    };
  }

  return { json: { payee, accountNumber, ifsc, amount, confidence, status: 'Done' } };
} catch (e) {
  return {
    json: {
      payee: '',
      accountNumber: '',
      ifsc: '',
      amount: '',
      confidence: 0,
      status: 'Error: model response not parseable - ' + e.message,
    },
  };
}

